<?php $editing = !empty($editCommission); ?>
<div class="page-header"><div><h2>Commissions</h2><p>Payout tracking, statement months, and ownership of commissionable revenue.</p></div></div>
<div class="grid-two">
<div class="card"><h3><?= $editing ? 'Edit Commission' : 'Add Commission' ?></h3><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="<?= $editing ? 'update' : 'create' ?>"><?php if ($editing): ?><input type="hidden" name="id" value="<?= e((string)$editCommission['id']) ?>"><?php endif; ?><select name="agent_user_id"><option value="">Agent</option><?php foreach ($assignableUsers as $user): ?><option value="<?= e((string)$user['id']) ?>" <?= ((string)($editCommission['agent_user_id'] ?? '') === (string)$user['id']) ? 'selected' : '' ?>><?= e($user['full_name']) ?> · <?= e($user['role']) ?></option><?php endforeach; ?></select><input name="client_name" placeholder="Client Name" value="<?= e($editCommission['client_name'] ?? '') ?>" required><input name="deal_name" placeholder="Deal Name" value="<?= e($editCommission['deal_name'] ?? '') ?>" required><input name="amount" placeholder="Amount" value="<?= e((string)($editCommission['amount'] ?? '')) ?>"><select name="payout_status"><?php foreach (['Unpaid','Scheduled','Paid'] as $status): ?><option value="<?= e($status) ?>" <?= (($editCommission['payout_status'] ?? 'Unpaid')===$status)?'selected':''; ?>><?= e($status) ?></option><?php endforeach; ?></select><input name="statement_month" placeholder="YYYY-MM" value="<?= e($editCommission['statement_month'] ?? '') ?>"><textarea name="notes" placeholder="Notes"><?= e($editCommission['notes'] ?? '') ?></textarea><div class="actions"><button type="submit"><?= $editing ? 'Save Changes' : 'Create Commission' ?></button><?php if ($editing): ?><a class="btn-muted" href="index.php?page=commissions">Cancel</a><?php endif; ?></div></form></div>
<div class="card"><h3>Commission Ledger</h3><table><thead><tr><th>Agent</th><th>Client</th><th>Deal</th><th>Amount</th><th>Status</th><th></th></tr></thead><tbody><?php foreach ($commissions as $row): ?><tr><td><?= e($row['agent_name']) ?></td><td><?= e($row['client_name']) ?></td><td><?= e($row['deal_name']) ?><div class="muted"><?= e($row['statement_month']) ?></div></td><td><?= money($row['amount']) ?></td><td><span class="tag"><?= e($row['payout_status']) ?></span></td><td class="table-actions"><a href="index.php?page=commissions&id=<?= e((string)$row['id']) ?>">Edit</a><?php if (App\Core\Auth::can('commissions','delete')): ?><form method="post" onsubmit="return confirm('Delete this commission?');"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= e((string)$row['id']) ?>"><button class="btn-danger" type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
</div>
